package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class GsonBuilderTest {

  @Test
  void testDisableJdkUnsafe() throws Exception {
    GsonBuilder gsonBuilder = new GsonBuilder();

    // Use reflection to check initial value of useJdkUnsafe
    Field useJdkUnsafeField = GsonBuilder.class.getDeclaredField("useJdkUnsafe");
    useJdkUnsafeField.setAccessible(true);
    boolean initialValue = useJdkUnsafeField.getBoolean(gsonBuilder);

    // Call disableJdkUnsafe and assert returned instance is the same
    GsonBuilder returned = gsonBuilder.disableJdkUnsafe();
    assertSame(gsonBuilder, returned);

    // Assert useJdkUnsafe is now false
    boolean updatedValue = useJdkUnsafeField.getBoolean(gsonBuilder);
    assertFalse(updatedValue);

    // If initial value was already false, it should remain false
    if (!initialValue) {
      assertFalse(updatedValue);
    }
  }
}
